module asyn_fifo #(
    parameter	WIDTH = 8,
    parameter 	DEPTH = 16,
    parameter ADDR_WIDTH = $clog2(DEPTH)
) (
    input 					wclk,
    input 					rclk,
    input 					wrstn,
    input					rrstn,
    input 					winc,
    input 			 		rinc,
    input 		[WIDTH-1:0]	wdata,
    output reg wfull,
    output reg rempty,
    output reg [WIDTH-1:0]	rdata
);

reg [WIDTH-1:0] ram [DEPTH-1:0];
reg [ADDR_WIDTH-1:0] wptr, rptr;
wire [ADDR_WIDTH-1:0] waddr, raddr;

always @(posedge wclk or negedge wrstn) begin
    if (!wrstn) begin
        wptr <= 0;
    end else if (winc) begin
        wptr <= wptr + 1'b1;
    end
end

always @(posedge rclk or negedge rrstn) begin
    if (!rrstn) begin
        rptr <= 0;
    end else if (rinc) begin
        rptr <= rptr + 1'b1;
    end
end

reg [ADDR_WIDTH-1:0] rptr_rsync1, rptr_rsync2;
always @(posedge wclk or negedge wrstn) begin
    if (!wrstn) begin
        rptr_rsync1 <= 0;
        rptr_rsync2 <= 0;
    end else begin
        rptr_rsync1 <= rptr;
        rptr_rsync2 <= rptr_rsync1;
    end
end

reg [ADDR_WIDTH-1:0] wptr_wsync1, wptr_wsync2;
always @(posedge rclk or negedge rrstn) begin
    if (!rrstn) begin
        wptr_wsync1 <= 0;
        wptr_wsync2 <= 0;
    end else begin
        wptr_wsync1 <= wptr;
        wptr_wsync2 <= wptr_wsync1;
    end
end

assign raddr = rptr_rsync2;
always @(posedge rclk or negedge rrstn) begin
    if (!rrstn) begin
        rdata <= 0;
    end else begin
        rdata <= ram[raddr];
    end
end

assign waddr = wptr_wsync2;
always @(posedge wclk or negedge wrstn) begin
    if (!wrstn) begin
        ram[waddr] <= 0;
    end else if (winc) begin
        ram[waddr] <= wdata;
    end
end

always @(*) begin
    if (wptr_wsync2 == rptr_rsync2) begin
        if (winc && !rinc) begin
            wfull <= 1'b1;
            rempty <= 1'b0;
        end else begin
            wfull <= 1'b0;
            rempty <= 1'b1;
        end
    end else if (wptr_wsync2 > rptr_rsync2) begin
        if (wptr_wsync2 - rptr_rsync2 == 1) begin
            wfull <= 1'b1;
            rempty <= 1'b0;
        end else begin
            wfull <= 1'b0;
            rempty <= 1'b0;
        end
    end else begin
        if (rptr_rsync2 - wptr_wsync2 == 1) begin
            wfull <= 1'b0;
            rempty <= 1'b1;
        end else begin
            wfull <= 1'b0;
            rempty <= 1'b0;
        end
    end
end

endmodule

module dual_port_RAM #(parameter DEPTH = 16,  parameter WIDTH = 8)
(
	 input wclk	,
	 input wenc	,
	 input [$clog2(DEPTH)-1:0] waddr  ,
	 input [WIDTH-1:0] wdata ,
	 input rclk	,
	 input renc	,
	 input [$clog2(DEPTH)-1:0] raddr ,
	 output reg [WIDTH-1:0] rdata 		
);

reg [WIDTH-1:0] RAM_MEM [0:DEPTH-1];

always @(posedge wclk) begin
	if(wenc)
		RAM_MEM[waddr] <= wdata;
end 

always @(posedge rclk) begin
	if(renc)
		rdata <= RAM_MEM[raddr];
end 

endmodule
